Rabin-Karp: Full Picture
def rabin_karp(T, P, b=256, q=101):
    n, m = len(T), len(P)
    h_P = hash_str(P, b, q)
    h_W = hash_str(T[:m], b, q)
    matches = []

    for i in range(n - m + 1):
        if h_W == h_P:
            if T[i:i+m] == P:    # verify (avoid false positives)
                matches.append(i)
        if i &lt; n - m:
            # roll the hash
            h_W = (b * (h_W - ord(T[i]) * pow(b, m-1, q)) + ord(T[i+m])) % q

    return matches

Expected time: O(n + m) — one pass, O(1) per step, rare verifications.
False positives (hash collision, no match): re-reduced by choosing large prime \(q\).

The Backtracking Template
def explore(partial_solution):
    if is_complete(partial_solution):
        record(partial_solution)          # found a solution!
        return

    for choice in get_choices(partial_solution):
        if is_valid(partial_solution, choice):
            partial_solution.add(choice)    # make the choice
            explore(partial_solution)       # explore further
            partial_solution.remove(choice) # undo (backtrack)

The “undo” step is what makes backtracking work. We explore, retreat, and try something else.

Maze — Python Code
def solve(r, c, path):
  if not (0 &lt;= r &lt; 16 and 0 &lt;= c &lt; 16) 
    or maze[r][c] == 'X' or (r, c) in path:
   return False

  path.append((r, c))

  # Base Case: Found the Exit
  if maze[r][c] == 'E':
   return True

  # Explore: Up, Down, Left, Right
  for dr, dc in [(0, 1), (1, 0), (0, -1), (-1, 0)]:
   if solve(r + dr, c + dc, path):
    return True

  # Backtrack
  path.pop()
  return False

solution_path = []
rc = solve(0, 0, solution_path)
if rc: print("Path to exit:", solution_path)
else: print("No path found.")

Sudoku — Simplified Code
def solve_sudoku(board):
    empty = find_empty(board)
    if not empty:
        return True   # all cells filled → solution!

    row, col = empty

    for digit in range(1, 10):
        if is_valid_placement(board, row, col, digit):
            board[row][col] = digit

            # PRUNING: check if any cell now has 0 options
            if not any_cell_has_no_options(board):
                if solve_sudoku(board):   # recurse
                    return True

            board[row][col] = 0   # ← backtrack

    return False

any_cell_has_no_options is the pruning check — it looks ahead without committing.

Graph Colouring — Code
def is_safe(v, graph, c):
    for neighbor in graph[v]:
        if colors[neighbor] == c:
            return False
    return True


def solve_graph_coloring(graph, k, v=0):
    # Base Case: All vertices are colored
    if v == len(graph):
        return True

    # Try different colors for vertex v
    for c in range(1, k + 1):
        if is_safe(v, graph, c):
            colors[v] = c  # Choose

            if solve_graph_coloring(graph, k, v + 1):  # Explore
                return True

            colors[v] = 0  # Backtrack (Un-choose)

    return False

graph = [[2], [3, 4], [0, 5], [1, 4], [1, 3], [2]]
colors = [0] * len(graph)
print(solve_graph_coloring(graph, 2), colors)
colors = [0] * len(graph)
print(solve_graph_coloring(graph, 3), colors)

The Problem: Same Logic, Different Types
Imagine you want to print the last element of an array. You write this:
public static void printLast(int[] arr) {
    System.out.println(arr[arr.length - 1]);
}
Then your classmate asks: “Can it work with Strings?”

You write another version:
public static void printLast(String[] arr) {
    System.out.println(arr[arr.length - 1]);
}
The logic is identical. Only the type changed.

Method Overloading: A Quick Recap
Method overloading lets you define multiple methods with the same name but different parameter types.
public static int findMax(int[] arr) {
    int max = arr[0];
    for (int x : arr) if (x &gt; max) max = x;
    return max;
}

public static double findMax(double[] arr) {
    double max = arr[0];
    for (double x : arr) if (x &gt; max) max = x;
    return max;
}
Java picks the right version at compile time based on the argument type.

Using a Generic Method
Java infers the type from what you pass in — no special syntax needed at the call site.
Integer[] nums    = {10, 20, 30};
String[]  words   = {"apple", "banana", "cherry"};
Double[]  prices  = {1.99, 4.49, 2.75};

printLast(nums);    // prints 30
printLast(words);   // prints cherry
printLast(prices);  // prints 2.75







Note


T must be an object type (like Integer, String, Double) — not a primitive (int, double). That’s why we use Integer[] instead of int[].

Generic findMax: One Method for All
Let’s rewrite findMax generically. We need T to be comparable:
public static &lt;T extends Comparable&lt;T&gt;&gt; T findMax(T[] arr) {
    T max = arr[0];
    for (T x : arr) if (x.compareTo(max) &gt; 0) max = x;
    return max;
}

T extends Comparable&lt;T&gt; is a bounded type parameter — it means:

“T can be any type, as long as it knows how to compare itself to another T.”

Integer, String, Double all implement Comparable — so they all work.

From Generic Methods to Generic Classes
Sometimes the type is a property of the whole class, not just one method.
Think about a box that can hold anything:
public class Box {
    private Object contents;

    public void put(Object item) { this.contents = item; }
    public Object get()          { return this.contents; }
}

Problem: get() returns Object, so you must cast every time:
Box b = new Box();
b.put("Hello");
String s = (String) b.get();  // cast required — easy to get wrong

Generic Classes: The Fix
Declare the type parameter at the class level using &lt;T&gt;:
public class Box&lt;T&gt; {
    private T contents;
    public void put(T item)  { this.contents = item; }
    public T    get()        { return this.contents; }
}

Now each Box is locked to one type — no casting needed:
Box&lt;String&gt;  strBox = new Box&lt;&gt;();
Box&lt;Integer&gt; intBox = new Box&lt;&gt;();

strBox.put("Hello");
intBox.put(42);

String  s = strBox.get();  // no cast
Integer n = intBox.get();  // no cast

Generic Classes: Multiple Type Parameters
A class can have more than one type parameter. Use different letters by convention:
public class Pair&lt;A, B&gt; {
    private A first;
    private B second;

    public Pair(A first, B second) {
        this.first  = first;
        this.second = second;
    }

    public A getFirst()  { return first; }
    public B getSecond() { return second; }
}
Pair&lt;String, Integer&gt; grade = new Pair&lt;&gt;("Alice", 95);
System.out.println(grade.getFirst());   // Alice
System.out.println(grade.getSecond());  // 95

You’ve Been Using Generic Classes All Along

ArrayList&lt;T&gt; — a list that holds objects of type T


The diamond &lt;&gt; on the right lets Java infer the type from the left side:
// These are all generic classes in the Java standard library:
ArrayList&lt;String&gt;  names   = new ArrayList&lt;&gt;();
ArrayList&lt;Integer&gt; scores  = new ArrayList&lt;&gt;();
You’ve been using generics the whole time — now you know how they work under the hood.

The Console I/O You Already Know
Before diving into files, recall how you handled console I/O in CS1:
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        // READING from the keyboard
        Scanner sc = new Scanner(System.in);
        String name = sc.nextLine();
        int age = sc.nextInt();

        // WRITING to the console
        System.out.println("Hello, " + name);
        System.out.printf("Age: %d%n", age);
